function maxArea(height: number[]): number {
  let i = 0, j = height.length - 1, best = 0;
  while (i < j) {
    const h = Math.min(height[i], height[j]);
    const area = h * (j - i);
    if (area > best) best = area;
    if (height[i] < height[j]) i++; else j--;
  }
  return best;
}
